redis_client = Redis.from_url(app.config['REDIS_URL'])

def cached(ttl=None):
    def decorator(func):
        def wrap(*args, **kwargs):
            key = f'cache_{func.__name__}'
            if redis_client.exists(key) and ttl is not None:
                data = redis_client.get(key)
                return jsonify(data)

            result = func(*args, **kwargs)
            if result and ttl is not None:
                redis_client.set(key, json.dumps(result), ex=ttl)
            return result
        return wrap
    return decorator

